package com.evolua.chat.infrastructure.persistence; import com.evolua.chat.domain.Message; import com.evolua.chat.domain.MessageRepository; import java.util.List; import org.springframework.stereotype.Repository; @Repository public class MessagePersistenceAdapter implements MessageRepository { private final MessageMongoRepository repository; public MessagePersistenceAdapter(MessageMongoRepository repository) { this.repository = repository; } public Message save(Message item) { MessageDocument document = new MessageDocument(); document.setId(item.id()); document.setUserId(item.userId()); document.setRecipientId(item.recipientId()); document.setContent(item.content()); document.setCreatedAt(item.createdAt()); MessageDocument saved = repository.save(document); return new Message(saved.getId(), saved.getUserId(), saved.getRecipientId(), saved.getContent(), saved.getCreatedAt()); } public List<Message> findAllByUserId(String userId) { return repository.findAllByUserId(userId).stream().map(saved -> new Message(saved.getId(), saved.getUserId(), saved.getRecipientId(), saved.getContent(), saved.getCreatedAt())).toList(); } }
